function.arguments:
{"code": "import json

# Load package data
with open('var_functions.query_db:20', 'r') as f:
    package_data = json.load(f)

print('Total packages:', len(package_data))

# Parse the JSON strings and filter
release_packages = []
for pkg in package_data:
    try:
        # Parse Licenses
        licenses_str = pkg['Licenses']
        if isinstance(licenses_str, str):
            licenses = json.loads(licenses_str)
        else:
            licenses = licenses_str

        # Parse VersionInfo
        version_info_str = pkg['VersionInfo']
        if isinstance(version_info_str, str):
            version_info = json.loads(version_info_str)
        else:
            version_info = version_info_str

        # Check if MIT and release
        if 'MIT' in licenses and version_info.get('IsRelease', False):
            release_packages.append({
                'System': pkg['System'],
                'Name': pkg['Name'],
                'Version': pkg['Version'],
                'Licenses': licenses,
                'IsRelease': version_info['IsRelease']
            })
    except Exception as e:
        continue

print('Release packages with MIT:', len(release_packages))
print('\nFirst few:')
for i, pkg in enumerate(release_packages[:5]):
    print(f"{i+1}. {pkg['Name']} v{pkg['Version']}")"}

